@using sv_25ef4913beb9443e88edc254fcefd7ed.Components.Pages.Board

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-1">@Task.Priority</span>
        <span class="small text-muted">@Task.DueDate.ToString("MMM dd")</span>
        <div class="mt-2 d-flex gap-1">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="MoveLeftClicked">← Move Left</button>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="MoveRightClicked">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async System.Threading.Tasks.Task MoveLeftClicked() => await OnMoveLeft.InvokeAsync(Task.Id);
    private async System.Threading.Tasks.Task MoveRightClicked() => await OnMoveRight.InvokeAsync(Task.Id);
}

@using sv_25ef4913beb9443e88edc254fcefd7ed.Components.Pages.Board

@if (!IsVisible)
{
    <button class="btn btn-outline-primary btn-sm w-100" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="card border-primary mt-2">
        <div class="card-body p-2">
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
            </div>
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
            </div>
            <div class="mb-2">
                <select class="form-select form-select-sm" @bind="priority">
                    <option value="High">High</option>
                    <option value="Medium">Medium</option>
                    <option value="Low">Low</option>
                </select>
            </div>
            <div class="mb-2">
                <input type="date" class="form-control form-control-sm" @bind="dueDate" />
            </div>
            <div class="d-flex gap-1">
                <button class="btn btn-primary btn-sm" @onclick="Save" disabled="@isSaving">Save</button>
                <button class="btn btn-secondary btn-sm" @onclick="Cancel" disabled="@isSaving">Cancel</button>
            </div>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter, EditorRequired] public ITaskService TaskService { get; set; } = default!;

    private bool IsVisible;
    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        IsVisible = false;
        ResetForm();
    }

    private async System.Threading.Tasks.Task Save()
    {
        if (string.IsNullOrWhiteSpace(title)) return;

        isSaving = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(title.Trim(), assignee.Trim(), priority, dueDate);
            await OnTaskCreated.InvokeAsync(created);
            IsVisible = false;
            ResetForm();
        }
        finally
        {
            isSaving = false;
        }
    }

    private void ResetForm()
    {
        title = "";
        assignee = "";
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
    }
}

@using sv_25ef4913beb9443e88edc254fcefd7ed.Components.Pages.Board

<div class="d-flex flex-wrap gap-3 mb-3 p-3 bg-light rounded">
    <div><strong>Total:</strong> @Tasks.Count</div>
    <div><strong>To Do:</strong> @Tasks.Count(t => t.Status == "To Do")</div>
    <div><strong>In Progress:</strong> @Tasks.Count(t => t.Status == "In Progress")</div>
    <div><strong>Done:</strong> @Tasks.Count(t => t.Status == "Done")</div>
    <div class="@(OverdueCount > 0 ? "text-danger" : "")">
        <strong>Overdue:</strong> @OverdueCount
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();

    private int OverdueCount => Tasks.Count(t => t.DueDate < DateTime.Today && t.Status != "Done");
}

@using sv_25ef4913beb9443e88edc254fcefd7ed.Components.Pages.Board

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body" style="overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          OnMoveLeft="OnMoveLeft"
                          OnMoveRight="OnMoveRight" />
            }
            <AddTaskForm Status="@ColumnName"
                         TaskService="TaskService"
                         OnTaskCreated="OnTaskCreated" />
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = default!;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter, EditorRequired] public ITaskService TaskService { get; set; } = default!;
}

