@using sv_25ef4913beb9443e88edc254fcefd7ed.Components.Pages.Board

@if (!IsVisible)
{
    <button class="btn btn-outline-primary btn-sm w-100 mt-2" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="card border-primary mt-2">
        <div class="card-body p-2">
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
            </div>
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
            </div>
            <div class="mb-2">
                <select class="form-select form-select-sm" @bind="priority">
                    <option value="High">High</option>
                    <option value="Medium">Medium</option>
                    <option value="Low">Low</option>
                </select>
            </div>
            <div class="mb-2">
                <input type="date" class="form-control form-control-sm" @bind="dueDate" />
            </div>
            <div class="d-flex gap-1">
                <button class="btn btn-primary btn-sm" @onclick="Save" disabled="@isSaving">Save</button>
                <button class="btn btn-secondary btn-sm" @onclick="Cancel" disabled="@isSaving">Cancel</button>
            </div>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter, EditorRequired] public ITaskService TaskService { get; set; } = default!;

    private bool IsVisible;
    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        IsVisible = false;
        ResetForm();
    }

    private async System.Threading.Tasks.Task Save()
    {
        if (string.IsNullOrWhiteSpace(title)) return;

        isSaving = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(title.Trim(), assignee.Trim(), priority, dueDate);
            await OnTaskCreated.InvokeAsync(created);
            IsVisible = false;
            ResetForm();
        }
        finally
        {
            isSaving = false;
        }
    }

    private void ResetForm()
    {
        title = "";
        assignee = "";
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
    }
}

